// src/routes/api/payment/handler.ts
var orderService2 = new OrderService();
var initiatePaymentHandler = {
  handler: async (request, reply) => {
    try {
      const body = request.body;
      const userId = body.userId;
      if (!userId || typeof userId !== "number") {
        return sendError(
          "INVALID_REQUEST",
          "User ID is required and must be a number",
          reply,
          400
        );
      }
      let totalAmountCurrency = body.totalAmountCurrency;
      if (!totalAmountCurrency) {
        const derived = currencyService.getCurrencyByPaymentMethod(
          body.paymentMethod
        );
        if (!derived) {
          return sendError(
            "INVALID_REQUEST",
            `Cannot determine currency for payment method: ${body.paymentMethod}`,
            reply,
            400
          );
        }
        totalAmountCurrency = derived;
      }
      let totalAmount = body.totalAmount;
      if (totalAmount === void 0 || totalAmount === null) {
        try {
          totalAmount = await orderService2.calculateTotalAmount(
            body.products,
            totalAmountCurrency
          );
        } catch (err) {
          const msg = err instanceof Error ? err.message : "Failed to calculate total amount";
          return sendError("CALCULATION_ERROR", msg, reply, 400);
        }
      }
      const orderInput = {
        userId,
        paymentMethod: body.paymentMethod,
        totalAmount,
        totalAmountCurrency,
        billingAddress: body.billingAddress,
        shippingAddress: body.shippingAddress,
        products: body.products,
        notes: body.notes
      };
      const paymentResult = await paymentService.initiatePayment(orderInput, userId);
      return sendSuccess(
        paymentResult,
        "Payment initiated successfully",
        reply,
        200
      );
    } catch (error48) {
      const message = error48 instanceof Error ? error48.message : "Payment initiation failed";
      const statusCode = error48 instanceof PaymentValidationError ? 400 : 500;
      return sendError("PAYMENT_ERROR", message, reply, statusCode);
    }
  }
};

