// src/routes/api/users/index.ts
async function usersRoute(fastify) {
  fastify.withTypeProvider().get(
    "/",
    {
      schema: getUserByEmailSchema
    },
    async (request, reply) => {
      if (request.query.email) {
        const user = await db.select({
          id: usersTable.id,
          name: usersTable.name,
          email: usersTable.email
        }).from(usersTable).where(eq7(usersTable.email, request.query.email));
        return sendSuccess(user, "User retrieved successfully", reply, 200);
      }
      const allUsers = await db.select({
        id: usersTable.id,
        name: usersTable.name,
        email: usersTable.email
      }).from(usersTable);
      sendSuccess(allUsers, "Users retrieved successfully", reply, 200);
    }
  );
  fastify.withTypeProvider().post(
    "/",
    {
      schema: createUserSchema
    },
    async (request, reply) => {
      const { name, email: email3, password } = request.body;
      const existingUser = await db.select().from(usersTable).where(eq7(usersTable.email, email3));
      if (existingUser.length > 0) {
        return sendError(
          "User with this email already exists",
          "CONFLICT",
          reply,
          409
        );
      }
      const hashedPassword = hashPassword(password);
      const newUser = await db.insert(usersTable).values({
        name,
        email: email3,
        password: hashedPassword,
        contact: "wewewe"
        // Placeholder, adjust as needed
      }).returning({
        id: usersTable.id,
        name: usersTable.name,
        email: usersTable.email
      });
      sendSuccess(newUser[0], "User created successfully", reply, 201);
    }
  );
  fastify.withTypeProvider().put(
    "/:id",
    {
      schema: updateUserSchema
    },
    async (request, reply) => {
      const { id } = request.params;
      const { name, email: email3 } = request.body;
      const updatedUser = await db.update(usersTable).set({ name, email: email3 }).where(eq7(usersTable.id, id)).returning({
        id: usersTable.id,
        name: usersTable.name,
        email: usersTable.email
      });
      if (updatedUser.length === 0) {
        return sendError("User not found", "NOT_FOUND", reply, 404);
      }
      sendSuccess(updatedUser[0], "User updated successfully", reply, 200);
    }
  );
  fastify.withTypeProvider().delete(
    "/:id",
    {
      schema: deleteUserSchema
    },
    async (request, reply) => {
      const { id } = request.params;
      const deletedUser = await db.delete(usersTable).where(eq7(usersTable.id, id)).returning({
        id: usersTable.id
      });
      if (deletedUser.length === 0) {
        return sendError("User not found", "NOT_FOUND", reply, 404);
      }
      sendSuccess(
        { id: deletedUser[0].id, deleted: true },
        "User deleted successfully",
        reply,
        200
      );
    }
  );
}

// src/routes/checkout/index.ts
import { eq as eq8 } from "drizzle-orm";
var SuccessQuery = external_exports.object({ orderId: external_exports.string().or(external_exports.number()) });
async function checkoutRoutes(fastify) {
  fastify.get(
    "/success",
    {
      schema: {
        querystring: SuccessQuery,
        description: "Simple confirmation page for a completed checkout",
        tags: ["Checkout"]
      }
    },
    async (request, reply) => {
      const parsed = SuccessQuery.safeParse(request.query);
      if (!parsed.success) {
        return reply.status(400).type("text/html").send(`<h1>Missing orderId</h1>`);
      }
      const orderId = Number(parsed.data.orderId);
      try {
        const [payment] = await db.select().from(paymentsTable).where(eq8(paymentsTable.orderId, orderId)).orderBy(paymentsTable.createdAt).limit(1);
        if (!payment) {
          return reply.type("text/html").send(`
            <h1>Payment not found</h1>
            <p>No payment record found for orderId=${orderId}</p>
          `);
        }
        return reply.type("text/html").send(`
          <h1>Payment Confirmation</h1>
          <p>Order ID: ${orderId}</p>
          <p>Payment ID: ${payment.id}</p>
          <p>Status: ${payment.status}</p>
          <p>Amount: ${payment.amount}</p>
        `);
      } catch (err) {
        request.log.error(err);
        return reply.status(500).type("text/html").send(`<h1>Error</h1><p>Failed to load confirmation</p>`);
      }
    }
  );
}

